# Generated by agint:generate-lab. Shared task surface for integration labs.
#
# The create/destroy/status/check/exec/ssh (and optional reload-check) commands are
# defined ONCE here; each lab module calls build_collection() (VM/host) or
# build_kube_collection() (Kubernetes) with its constants. Edit this file to change
# behavior for every integration lab at once; edit the scenario/component for
# lab-specific setup.
from __future__ import annotations

import os
import shlex
import tempfile
from collections.abc import Iterable
from urllib.parse import quote

from invoke.collection import Collection
from invoke.context import Context
from invoke.exceptions import UnexpectedExit
from invoke.tasks import Task, task

from tasks.e2e_framework import tool
from tasks.e2e_framework.aws.deploy import deploy
from tasks.e2e_framework.destroy import destroy as e2e_destroy
from tasks.e2e_framework.tool import get_host

# Public API imported by the thin per-lab modules. Declared so the dead-code linter
# (vulture) does not flag a builder as unused in a repo that only has one lab type.
__all__ = ["build_collection", "build_kube_collection"]

DEFAULT_DD_SITE = "ddintdev.datadoghq.com"


def _collection_name(name: str) -> str:
    # Register the invoke collection under a dashed name (aws_neuron -> aws-neuron) so the CLI
    # command is deterministic and does not depend on invoke's auto_dash_names setting. The
    # generated report advertises this same dashed name.
    return name.replace("_", "-")


DEFAULT_STATUS_COMMAND = "sudo datadog-agent status"
SSH_OPTIONS = "-o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o LogLevel=ERROR"
KUBERNETES_NAMESPACE = "datadog"
# helm.NewKubernetesAgent names the Linux node Agent DaemonSet and ServiceAccount "dda-linux-datadog".
AGENT_DAEMONSET = "dda-linux-datadog"


# --------------------------------------------------------------------------- #
# VM / host-SSH labs
# --------------------------------------------------------------------------- #
def _missing_outputs_message(role: str) -> str:
    return (
        "create did not complete successfully; stack outputs are missing. "
        f"Expected host output for role {role!r}. Check the create failure before running status/check/exec/ssh."
    )


def _ssh_base(ctx: Context, scenario_name: str, role: str, stack_name: str | None = None) -> str:
    try:
        host = get_host(ctx, role, scenario_name, stack_name)
    except (KeyError, UnexpectedExit) as exc:
        # KeyError: outputs exist but lack this role. UnexpectedExit: `pulumi stack export`
        # failed (no/partial stack). Both mean create did not complete successfully.
        raise RuntimeError(_missing_outputs_message(role)) from exc
    command = f"ssh {SSH_OPTIONS} {host.user}@{host.address}"
    if host.port:
        command += f" -p {host.port}"
    return command


def _run_remote(ctx: Context, scenario_name: str, role: str, command: str, stack_name: str | None = None):
    if not command:
        raise ValueError("command is required")
    # The command must be the ssh remote command (a single quoted argument after the
    # destination). Do NOT insert a "--" here: ssh treats everything after the destination as
    # the remote command, so a leading "--" is sent to the login shell (`$SHELL -c '-- ...'`),
    # which rejects it as an invalid option and breaks status/check/exec/reload-check.
    return ctx.run(f"{_ssh_base(ctx, scenario_name, role, stack_name)} {shlex.quote(command)}")


def _datadog_site() -> str:
    return os.environ.get("DD_SITE") or os.environ.get("DATADOG_SITE") or DEFAULT_DD_SITE


def _datadog_base_url() -> str:
    site = _datadog_site().removeprefix("https://").removeprefix("http://")
    if site.startswith("app.") or site.startswith("ddintdev."):
        return f"https://{site}"
    return f"https://app.{site}"


def _datadog_host_url(hostname: str) -> str:
    return f"{_datadog_base_url()}/infrastructure?tags=host%3A{quote(hostname)}"


def _best_effort_datadog_hostname(ctx: Context, scenario_name: str, role: str, stack_name: str | None = None) -> str:
    metadata_command = (
        "token=$(curl -fsS -X PUT http://169.254.169.254/latest/api/token "
        "-H 'X-aws-ec2-metadata-token-ttl-seconds: 60' --max-time 2 2>/dev/null || true); "
        "if [ -n \"$token\" ]; then "
        "curl -fsS -H \"X-aws-ec2-metadata-token: $token\" --max-time 2 "
        "http://169.254.169.254/latest/meta-data/instance-id || hostname -f 2>/dev/null || hostname; "
        "else hostname -f 2>/dev/null || hostname; fi"
    )
    try:
        result = _run_remote(ctx, scenario_name, role, metadata_command, stack_name=stack_name)
        hostname = result.stdout.strip().splitlines()[-1]
        if hostname:
            return hostname
    except Exception:
        pass
    try:
        host = get_host(ctx, role, scenario_name, stack_name)
        return host.address
    except Exception:
        return role


def _show_create_success_message(ctx: Context, scenario_name: str, role: str, stack_name: str | None = None) -> None:
    try:
        ssh_command = _ssh_base(ctx, scenario_name, role, stack_name)
        hostname = _best_effort_datadog_hostname(ctx, scenario_name, role, stack_name)
    except Exception as exc:
        print(f"Datadog host URL unavailable until stack outputs exist: {exc}")
        return
    print("\nLab created. Useful links:")
    print(f"  SSH: {ssh_command}")
    print(f"  Datadog host: {_datadog_host_url(hostname)}")
    print(
        "  Note: Whether the host appears depends on the API key configured for this lab, and data may take a minute to arrive.\n"
    )


def build_collection(
    *,
    name: str,
    scenario_name: str,
    check_command: str,
    remote_hostname: str,
    status_command: str = DEFAULT_STATUS_COMMAND,
    source: tuple[str, str, str] | None = None,
    reload_check: bool = False,
    extra_tasks: Iterable[Task] | None = None,
) -> Collection:
    """Build the standard invoke task surface for one VM/host integration lab.

    name: invoke sub-collection name (the integration), e.g. "redisdb" -> aws.integrations.redisdb.*
    scenario_name: registry key passed to deploy/get_host, e.g. "aws/integrations/redisdb".
    check_command / status_command: remote Agent commands run by check/status.
    remote_hostname: the framework export role get_host resolves (dd-Host-<role>).
    source: (url, ref, path) used by reload-check; required when reload_check=True.
    extra_tasks: optional already-decorated @task callables for a bespoke lab.
    """

    @task
    def create(
        ctx: Context,
        config_path: str | None = None,
        stack_name: str | None = None,
        pipeline_id: str | None = None,
        agent_version: str | None = None,
        debug: bool | None = False,
        agent_flavor: str | None = None,
        agent_config_path: str | None = None,
        local_package: str | None = None,
    ):
        """Create the integration lab by deploying the E2E scenario and print host inspection links."""
        full_stack_name = deploy(
            ctx,
            scenario_name,
            config_path=config_path,
            stack_name=stack_name,
            pipeline_id=pipeline_id,
            install_agent=True,
            agent_version=agent_version,
            debug=debug,
            use_fakeintake=False,
            agent_flavor=agent_flavor,
            agent_config_path=agent_config_path,
            local_package=local_package,
        )
        _show_create_success_message(ctx, scenario_name, remote_hostname, stack_name)
        return full_stack_name

    @task
    def destroy_lab(ctx: Context, config_path: str | None = None, stack_name: str | None = None):
        """Destroy resources owned by this integration lab."""
        return e2e_destroy(ctx, scenario_name=scenario_name, config_path=config_path, stack=stack_name)

    @task
    def status(ctx: Context, role: str = remote_hostname, stack_name: str | None = None):
        """Run the Agent status command on the Agent host and return the full output."""
        return _run_remote(ctx, scenario_name, role, status_command, stack_name=stack_name)

    @task
    def check(ctx: Context, role: str = remote_hostname, stack_name: str | None = None):
        """Run the configured Agent check on the Agent host."""
        return _run_remote(ctx, scenario_name, role, check_command, stack_name=stack_name)

    @task(name="exec")
    def exec_(ctx: Context, role: str = remote_hostname, command: str | None = None, stack_name: str | None = None):
        """Run an explicit command on a lab host role."""
        if command is None:
            raise ValueError("--command is required")
        return _run_remote(ctx, scenario_name, role, command, stack_name=stack_name)

    @task
    def ssh(ctx: Context, role: str = remote_hostname, stack_name: str | None = None, connect: bool = False):
        """Print or open SSH access for a lab host role."""
        command = _ssh_base(ctx, scenario_name, role, stack_name)
        print(command)
        if connect:
            return ctx.run(command, pty=True)
        return None

    collection = Collection(_collection_name(name))
    collection.add_task(create)
    collection.add_task(destroy_lab, name="destroy")
    collection.add_task(status)
    collection.add_task(check)
    collection.add_task(exec_, name="exec")
    collection.add_task(ssh)

    if reload_check:
        if not source:
            raise ValueError("reload_check=True requires source=(url, ref, path)")
        source_url, source_ref, source_path = source

        @task(name="reload-check")
        def reload_check_task(ctx: Context, role: str = remote_hostname, stack_name: str | None = None):
            """Manually reinstall the declared check source and run configcheck/check."""
            commands = [
                "set -euo pipefail",
                "workdir=$(mktemp -d)",
                "git clone " + shlex.quote(source_url) + " $workdir/src",
                "git -C $workdir/src checkout " + shlex.quote(source_ref),
                "sudo -u dd-agent datadog-agent integration install -r $workdir/src/" + shlex.quote(source_path),
                "sudo systemctl restart datadog-agent || sudo service datadog-agent restart",
                "sudo datadog-agent configcheck",
                check_command,
            ]
            return _run_remote(ctx, scenario_name, role, " && ".join(commands), stack_name=stack_name)

        collection.add_task(reload_check_task, name="reload-check")

    for extra in extra_tasks or []:
        collection.add_task(extra)

    return collection


# --------------------------------------------------------------------------- #
# Kubernetes (kubeconfig) labs
# --------------------------------------------------------------------------- #
def _kube_missing_outputs_message(cluster_output_key: str) -> str:
    return (
        "create did not complete successfully; stack outputs are missing. "
        f"Expected {cluster_output_key} with kubeConfig. Check the create failure before running status/check/exec/ssh."
    )


def _write_kubeconfig_from_outputs(outputs: dict, cluster_output_key: str, full_stack_name: str) -> str:
    if not outputs:
        raise RuntimeError(_kube_missing_outputs_message(cluster_output_key))
    try:
        cluster = outputs[cluster_output_key]
    except KeyError as exc:
        raise RuntimeError(_kube_missing_outputs_message(cluster_output_key)) from exc
    if not isinstance(cluster, dict) or "kubeConfig" not in cluster:
        raise RuntimeError(f"cluster output is missing kubeConfig: {cluster_output_key}")
    kubeconfig_dir = tempfile.mkdtemp(prefix=f"kubeconfig-{full_stack_name}-")
    kubeconfig_path = os.path.join(kubeconfig_dir, "config")
    with open(kubeconfig_path, "w") as f:
        f.write(cluster["kubeConfig"])
    os.chmod(kubeconfig_path, 0o600)
    os.environ["KUBECONFIG"] = kubeconfig_path
    return kubeconfig_path


def build_kube_collection(
    *,
    name: str,
    scenario_name: str,
    check_name: str,
    cluster_name: str,
    extra_tasks: Iterable[Task] | None = None,
) -> Collection:
    """Build the standard invoke task surface for one Kubernetes (kubeconfig) integration lab.

    create/ssh print an `export KUBECONFIG=<path>` command; status/check run through the Linux
    Datadog DaemonSet via kubectl; exec runs an explicit local kubectl command. No --role and no
    reload-check (Kubernetes labs reinstall through Helm/redeploy, not a host reload).
    """
    cluster_output_key = f"dd-Cluster-{cluster_name}"

    def _full_stack_name(stack_name: str | None = None) -> str:
        return tool.get_stack_name(stack_name, scenario_name)

    def _write_kubeconfig(ctx: Context, stack_name: str | None = None) -> str:
        full_stack_name = _full_stack_name(stack_name)
        try:
            outputs = tool.get_stack_json_outputs(ctx, full_stack_name)
        except UnexpectedExit as exc:
            raise RuntimeError(_kube_missing_outputs_message(cluster_output_key)) from exc
        return _write_kubeconfig_from_outputs(outputs, cluster_output_key, full_stack_name)

    def _show_connection_message(ctx: Context, stack_name: str | None = None) -> None:
        kubeconfig_path = _write_kubeconfig(ctx, stack_name)
        print(f"export KUBECONFIG={kubeconfig_path}")

    def _run_kubectl(ctx: Context, command: str, stack_name: str | None = None):
        if not command:
            raise ValueError("command is required")
        kubeconfig_path = _write_kubeconfig(ctx, stack_name)
        return ctx.run(f"kubectl --kubeconfig={shlex.quote(kubeconfig_path)} {command}")

    def _run_kubectl_args(ctx: Context, args: list[str], stack_name: str | None = None):
        return _run_kubectl(ctx, " ".join(shlex.quote(arg) for arg in args), stack_name=stack_name)

    @task
    def create(
        ctx: Context,
        config_path: str | None = None,
        stack_name: str | None = None,
        pipeline_id: str | None = None,
        agent_version: str | None = None,
        debug: bool | None = False,
        agent_flavor: str | None = None,
        agent_config_path: str | None = None,
        local_package: str | None = None,
    ):
        """Create the Kubernetes integration lab and print an export KUBECONFIG command."""
        full_stack_name = deploy(
            ctx,
            scenario_name,
            config_path=config_path,
            stack_name=stack_name,
            pipeline_id=pipeline_id,
            install_agent=True,
            agent_version=agent_version,
            debug=debug,
            use_fakeintake=False,
            agent_flavor=agent_flavor,
            agent_config_path=agent_config_path,
            local_package=local_package,
        )
        _show_connection_message(ctx, stack_name)
        return full_stack_name

    @task
    def destroy_lab(ctx: Context, config_path: str | None = None, stack_name: str | None = None):
        """Destroy resources owned by this integration lab."""
        return e2e_destroy(ctx, scenario_name=scenario_name, config_path=config_path, stack=stack_name)

    @task
    def status(ctx: Context, stack_name: str | None = None):
        """Run Agent status through the Datadog DaemonSet using the generated kubeconfig."""
        return _run_kubectl_args(
            ctx,
            ["exec", "-n", KUBERNETES_NAMESPACE, "ds/" + AGENT_DAEMONSET, "--", "agent", "status"],
            stack_name=stack_name,
        )

    @task
    def check(ctx: Context, stack_name: str | None = None):
        """Run the configured Agent check through the Datadog DaemonSet."""
        return _run_kubectl_args(
            ctx,
            ["exec", "-n", KUBERNETES_NAMESPACE, "ds/" + AGENT_DAEMONSET, "--", "agent", "check", check_name],
            stack_name=stack_name,
        )

    @task(name="exec")
    def exec_(ctx: Context, command: str | None = None, stack_name: str | None = None):
        """Run a kubectl command against the lab cluster, for example --command 'get pods -A'."""
        if command is None:
            raise ValueError("--command is required")
        return _run_kubectl(ctx, command, stack_name=stack_name)

    @task
    def ssh(ctx: Context, stack_name: str | None = None):
        """Print an export KUBECONFIG command for this Kubernetes lab."""
        _show_connection_message(ctx, stack_name)
        return None

    collection = Collection(_collection_name(name))
    collection.add_task(create)
    collection.add_task(destroy_lab, name="destroy")
    collection.add_task(status)
    collection.add_task(check)
    collection.add_task(exec_, name="exec")
    collection.add_task(ssh)

    for extra in extra_tasks or []:
        collection.add_task(extra)

    return collection
